5	use App\Domain\Models\Permission;
6	use App\Domain\Models\RolePermission;
7	use Illuminate\Database\Seeder;
8	
9	class PermissionSeeder extends Seeder
10	{
11	    public function run(): void
12	    {
13	        // ── Define all permissions ──────────────────────────────────
14	        $permissions = [
15	            // Service Areas
16	            ['slug' => 'service-areas.create', 'description' => 'Create service areas',     'group' => 'service-areas'],
17	            ['slug' => 'service-areas.update', 'description' => 'Update service areas',     'group' => 'service-areas'],
18	
19	            // Roles (system roles management)
20	            ['slug' => 'roles.create', 'description' => 'Create roles',     'group' => 'roles'],
21	            ['slug' => 'roles.update', 'description' => 'Update roles',     'group' => 'roles'],
22	
23	            // Resources
24	            ['slug' => 'resources.create',     'description' => 'Create resources',          'group' => 'resources'],
25	            ['slug' => 'resources.update',     'description' => 'Update resources',          'group' => 'resources'],
26	            ['slug' => 'resources.transition', 'description' => 'Transition resource status', 'group' => 'resources'],
27	
28	            // Pricing Baselines
29	            ['slug' => 'pricing-baselines.create', 'description' => 'Create pricing baselines', 'group' => 'pricing-baselines'],
30	            ['slug' => 'pricing-baselines.update', 'description' => 'Update pricing baselines', 'group' => 'pricing-baselines'],
31	        ];
32	
33	        foreach ($permissions as $p) {
34	            Permission::firstOrCreate(['slug' => $p['slug']], $p);
35	        }
36	
37	        // ── Assign permissions to roles ─────────────────────────────
38	        // admin gets everything implicitly — no rows needed.
39	
40	        $rolePermissions = [
41	            // group-leader: all write operations
42	            'group-leader' => [
43	                'service-areas.create', 'service-areas.update',
44	                'roles.create', 'roles.update',
45	                'resources.create', 'resources.update', 'resources.transition',
46	                'pricing-baselines.create', 'pricing-baselines.update',
47	            ],
48	            // staff: can create/update resources and pricing, transition status
49	            'staff' => [
50	                'resources.create', 'resources.update', 'resources.transition',
51	                'pricing-baselines.create', 'pricing-baselines.update',
52	            ],
53	            // user: read-only, no write permissions
54	        ];
55	
56	        foreach ($rolePermissions as $role => $slugs) {
57	            foreach ($slugs as $slug) {
58	                $perm = Permission::where('slug', $slug)->first();
59	                if ($perm) {
60	                    RolePermission::firstOrCreate([
61	                        'role'          => $role,
62	                        'permission_id' => $perm->id,
63	                    ]);
64	                }
65	            }
66	        }
67	    }
68	}
