11	#[Layout('layouts.app')]
12	#[Title('Create Booking')]
13	class BookingCreate extends Component
14	{
15	    use UsesApiClient;
16	    public int $step = 1;
17	    public array $lineItems = [];
18	    public string $couponCode = '';
19	    public string $notes = '';
20	    public ?int $selectedItemId = null;
21	    public string $bookingDate = '';
22	    public string $startTime = '';
23	    public string $endTime = '';
24	    public int $quantity = 1;
25	
26	    public array $totals = ['lines' => [], 'subtotal' => 0, 'tax_amount' => 0, 'discount' => 0, 'total' => 0, 'coupon_id' => null];
27	    public string $availabilityMsg = '';
28	    public string $couponMsg = '';
29	    public bool $couponValid = false;
30	    public string $error = '';
31	
32	    /**
33	     * Snapshot of bookable item names keyed by id, captured when the line
34	     * item is added to the cart. The Blade view reads from THIS map instead
35	     * of issuing a fresh `BookableItem::find()` per row, eliminating the
36	     * O(N) query explosion that used to happen on every wire:model update.
37	     */
38	    public array $itemNames = [];
39	
40	    public function mount(): void
41	    {
42	        $this->bookingDate = date('Y-m-d');
43	        $preselect = request()->query('item');
44	        if ($preselect) $this->selectedItemId = (int) $preselect;
45	    }
46	
47	    public function checkAvailability(): void
48	    {
49	        $this->availabilityMsg = '';
50	        if (!$this->selectedItemId || !$this->bookingDate) return;
51	
52	        $resp = $this->api()->post('/bookings/check-availability', [
53	            'bookable_item_id' => $this->selectedItemId,
54	            'booking_date' => $this->bookingDate,
55	            'start_time' => $this->startTime ?: null,
56	            'end_time' => $this->endTime ?: null,
57	            'quantity' => $this->quantity,
58	        ]);
59	
60	        if ($resp->failed()) { $this->availabilityMsg = 'Error checking availability.'; return; }
61	        $data = $resp->json();
62	        $this->availabilityMsg = ($data['available'] ?? false) ? 'Available' : 'Unavailable: ' . implode(' ', $data['conflicts'] ?? []);
63	    }
64	
65	    public function addLineItem(BookingService $booking): void
66	    {
67	        if (!$this->selectedItemId || !$this->bookingDate) return;
68	
69	        // Capture the item name ONCE at add-to-cart time so the view never
70	        // has to round-trip to the database. listActiveItems() is paginated
71	        // to a generous page size — for the catalog sizes this product
72	        // targets, the cache is effectively the entire menu.
73	        if (!isset($this->itemNames[$this->selectedItemId])) {
74	            $cached = $booking->listActiveItems(perPage: 200)->getCollection();
75	            foreach ($cached as $item) {
76	                $this->itemNames[$item->id] = $item->name;
77	            }
78	        }
79	
80	        $this->lineItems[] = [
81	            'bookable_item_id' => $this->selectedItemId,
82	            'booking_date' => $this->bookingDate,
83	            'start_time' => $this->startTime ?: null,
84	            'end_time' => $this->endTime ?: null,
85	            'quantity' => $this->quantity,
86	        ];
87	        $this->selectedItemId = null;
88	        $this->startTime = '';
89	        $this->endTime = '';
90	        $this->quantity = 1;
91	        $this->availabilityMsg = '';
92	        $this->recalculate();
93	    }
94	
95	    public function removeLineItem(int $index): void
96	    {
97	        unset($this->lineItems[$index]);
98	        $this->lineItems = array_values($this->lineItems);
99	        $this->recalculate();
100	    }
101	
102	    public function applyCoupon(): void
103	    {
104	        $this->couponMsg = '';
105	        $this->couponValid = false;
106	        if (!$this->couponCode || $this->totals['subtotal'] <= 0) return;
107	
108	        $resp = $this->api()->post('/bookings/validate-coupon', [
109	            'code' => $this->couponCode,
110	            'subtotal' => $this->totals['subtotal'],
111	        ]);
112	        if ($resp->failed()) { $this->couponMsg = 'Error validating coupon.'; return; }
113	        $data = $resp->json();
114	        if ($data['valid'] ?? false) {
115	            $this->couponValid = true;
116	            $this->couponMsg = "Coupon applied: -\${$data['discount']}";
117	            $this->recalculate();
118	        } else {
119	            $this->couponMsg = $data['error'] ?? 'Invalid coupon.';
120	        }
121	    }
122	
123	    public function recalculate(): void
124	    {
125	        if (empty($this->lineItems)) {
126	            $this->totals = ['lines' => [], 'subtotal' => 0, 'tax_amount' => 0, 'discount' => 0, 'total' => 0, 'coupon_id' => null];
127	            return;
128	        }
129	        $resp = $this->api()->post('/bookings/calculate-totals', [
130	            'line_items' => $this->lineItems,
131	            'coupon_code' => $this->couponValid ? $this->couponCode : null,
132	        ]);
133	        if ($resp->successful()) { $this->totals = $resp->json(); }
134	    }
135	
136	    public function nextStep(): void
137	    {
138	        if ($this->step === 1 && empty($this->lineItems)) { $this->error = 'Add at least one item.'; return; }
139	        $this->error = '';
140	        $this->step = min($this->step + 1, 3);
141	    }
142	
143	    public function prevStep(): void { $this->step = max($this->step - 1, 1); }
144	
145	    public function submitOrder(): void
146	    {
147	        $resp = $this->api()->post('/orders', [
148	            'line_items' => $this->lineItems,
149	            'coupon_code' => $this->couponValid ? $this->couponCode : null,
150	            'notes' => $this->notes ?: null,
151	        ]);
152	
153	        if ($resp->failed()) {
154	            $this->error = $resp->json('message') ?? 'Failed to create order.';
155	            return;
156	        }
157	        $order = $resp->json('data');
158	        session()->flash('flash_success', "Order {$order['order_number']} created.");
159	        $this->redirect('/orders/' . $order['id']);
160	    }
161	
162	    public function render(BookingService $booking)
163	    {
164	        $items = $booking->listActiveItems(perPage: 100)->getCollection();
165	        return view('livewire.booking.booking-create', ['items' => $items]);
166	    }
167	}
