170	    public function createOrder(int $userId, array $lineItems, ?int $groupLeaderId = null, ?int $serviceAreaId = null, ?string $couponCode = null, ?string $notes = null): Order
171	    {
172	        // Validate: a referenced group leader must actually hold that role + be active.
173	        if ($groupLeaderId !== null) {
174	            $leader = User::find($groupLeaderId);
175	            if (!$leader || !in_array($leader->role, ['group-leader', 'admin'], true) || !$leader->is_active) {
176	                throw ValidationException::withMessages([
177	                    'group_leader_id' => 'Assigned user is not an eligible group leader.',
178	                ]);
179	            }
180	
181	            // Enforce GroupLeaderAssignment: the leader must hold an active assignment
182	            // covering the order's service area. Admins bypass this check.
183	            // The check is skipped only if no service area is specified (free-form order).
184	            if ($leader->role !== 'admin' && $serviceAreaId !== null) {
185	                $hasAssignment = GroupLeaderAssignment::where('user_id', $leader->id)
186	                    ->where('service_area_id', $serviceAreaId)
187	                    ->where('is_active', true)
188	                    ->exists();
189	                if (!$hasAssignment) {
190	                    throw ValidationException::withMessages([
191	                        'group_leader_id' => 'Group leader has no active assignment for this service area.',
192	                    ]);
193	                }
194	            }
195	        }
196	
197	        $conflicts = $this->detectConflicts($lineItems);
198	        if (!empty($conflicts)) {
199	            throw ValidationException::withMessages(['conflicts' => array_values($conflicts)]);
200	        }
201	
202	        // Build pricing context: user tier flows through the resolver automatically.
