9	class OrderPolicy
10	{
11	    /**
12	     * Approval transitions — staff with a complete profile may operate on any
13	     * pending reservation in their workflow regardless of ownership. This is
14	     * the operational queue model: tickets land in the staff inbox and any
15	     * staff member on shift can clear them.
16	     */
17	    public const APPROVAL_TRANSITIONS = ['confirmed'];
18	
19	    /**
20	     * Can the user view this order?
21	     *
22	     *  - Admins → always
23	     *  - Owners → always (their own order)
24	     *  - Attributed group-leaders → always
25	     *  - Staff (with complete profile) → may view any PENDING order so they
26	     *    can review the queue before approving. Once the order is no longer
27	     *    pending, the narrower ownership/attribution rules kick back in.
28	     */
29	    public function view(User $user, Order $order): bool
30	    {
31	        if ($user->isAdmin()) return true;
32	        if ($order->user_id === $user->id) return true;
33	        if ($order->group_leader_id === $user->id) return true;
34	        if ($order->status === 'pending'
35	            && $user->role === 'staff'
36	            && $this->hasCompleteProfile($user)) {
37	            return true;
38	        }
39	        return false;
40	    }
41	
42	    /**
43	     * Operational transitions that physically move an order through fulfilment.
44	     * Reserved for staff+ with a complete profile AND ownership/attribution.
45	     * 'confirmed' is NOT in this set anymore — it lives in APPROVAL_TRANSITIONS
46	     * because approval is queue-based, not ownership-based.
47	     */
48	    public const OPERATIONAL_TRANSITIONS = ['checked_in', 'checked_out', 'completed'];
49	
50	    /**
51	     * Self-service transitions that owners may perform on their own orders.
52	     *  - 'pending'   : owner submits a draft for staff approval.
53	     *  - 'cancelled' : owner cancels their own order.
54	     */
55	    public const SELF_SERVICE_TRANSITIONS = ['pending', 'cancelled'];
56	
57	    /**
58	     * Can the user transition this order's status to $newStatus?
59	     *
60	     *  - Approval (pending → confirmed): any staff member with a complete
61	     *    profile, regardless of ownership. The pending queue is a shared
62	     *    workflow inbox, not a per-staff silo. Admins are also allowed.
63	     *  - Other operational (check_in/check_out/complete): staff+ with complete
64	     *    profile AND object access (admin OR owner OR attributed group-leader).
65	     *  - Self-service (pending submission, cancel): owners only.
66	     *  - Anything else: deny.
67	     */
68	    public function transition(User $user, Order $order, string $newStatus): bool
69	    {
70	        // Approval queue: any staff-with-profile (or admin) can clear any
71	        // pending reservation. We do NOT call canActOn() here because the
72	        // approval queue is intentionally NOT scoped by ownership.
73	        if (in_array($newStatus, self::APPROVAL_TRANSITIONS, true)) {
74	            if ($user->isAdmin()) return true;
75	            if ($user->role !== 'staff') return false;
76	            if (!$this->hasCompleteProfile($user)) return false;
77	            // Approval is only valid OUT of 'pending'. The state machine in
78	            // BookingService enforces this independently, but we double-check
79	            // here so a stray confirm against a non-pending order is denied
80	            // by authorization rather than reaching the transition validator.
81	            return $order->status === 'pending';
82	        }
83	
84	        // Other operational transitions: ownership/attribution still required.
85	        if (in_array($newStatus, self::OPERATIONAL_TRANSITIONS, true)) {
86	            if (!$user->isAtLeast('staff')) return false;
87	            if (!$this->hasCompleteProfile($user)) return false;
88	            return $this->canActOn($user, $order);
89	        }
90	
91	        // Self-service transitions: owner only
92	        if (in_array($newStatus, self::SELF_SERVICE_TRANSITIONS, true)) {
93	            if ($user->isAdmin()) return true;
94	            return $order->user_id === $user->id;
95	        }
96	
97	        // Any other transition is reserved for admin
98	        return $user->isAdmin();
99	    }
100	
101	    /**
102	     * Can the user process a refund?
103	     * Staff+ with object access.
104	     */
105	    public function refund(User $user, Order $order): bool
106	    {
107	        if (!$user->isAtLeast('staff')) return false;
108	        return $this->canActOn($user, $order);
109	    }
110	
111	    /**
112	     * Can the user mark an order as staff-unavailable?
113	     *
114	     * Restricted to the *operational* roles only — explicit 'staff' or
115	     * 'admin'. Group-leaders are deliberately excluded even though they
116	     * sit higher in the role hierarchy: marking an order unavailable is
117	     * a fulfilment-floor action, not a supervisory one, and the
118	     * accountability trail must point at the staff member who
119	     * physically observed the issue.
120	     */
121	    public function markUnavailable(User $user, Order $order): bool
122	    {
123	        if (!in_array($user->role, ['staff', 'admin'], true)) {
124	            return false;
125	        }
126	        return $this->canActOn($user, $order);
127	    }
128	
129	    private function canActOn(User $user, Order $order): bool
130	    {
131	        if ($user->isAdmin()) return true;
132	        if ($order->user_id === $user->id) return true;
133	        if ($order->group_leader_id === $user->id) return true;
134	        return false;
135	    }
136	
137	    private function hasCompleteProfile(User $user): bool
138	    {
139	        if ($user->isAdmin()) return true;
140	        $profile = StaffProfile::where('user_id', $user->id)->first();
141	        return $profile && $profile->isComplete();
142	    }
143	}
