88	    /** Calculate pricing totals for a set of line items + optional coupon.
89	     *
90	     *  $context (optional) feeds the pricing resolver:
91	     *      member_tier, package_code, headcount
92	     */
93	    public function calculateTotals(array $lineItems, ?string $couponCode = null, array $context = []): array
94	    {
95	        $subtotal = 0;
96	        $taxTotal = 0;
97	        $lines = [];
98	
99	        foreach ($lineItems as $li) {
100	            $item = BookableItem::findOrFail($li['bookable_item_id']);
101	            $qty = $li['quantity'] ?? 1;
102	
103	            // 1) Compute the BASE unit price from the item's intrinsic pricing.
104	            if ($item->isConsumable()) {
105	                $basePrice = (float) $item->unit_price;
106	            } elseif (!empty($li['start_time']) && !empty($li['end_time'])) {
107	                $hours = (strtotime($li['end_time']) - strtotime($li['start_time'])) / 3600;
108	                $basePrice = (float) $item->hourly_rate * max($hours, 0);
109	            } else {
110	                $basePrice = (float) $item->daily_rate;
111	            }
112	
113	            // 2) Resolve via the multi-dimensional rule engine. Per-line context
114	            //    inherits from the order-level context but a line may override.
115	            $lineCtx = array_merge($context, [
116	                'date'         => $li['booking_date'],
117	                'start_time'   => $li['start_time'] ?? null,
118	                'end_time'     => $li['end_time'] ?? null,
119	                'headcount'    => $li['headcount'] ?? ($context['headcount'] ?? $qty),
120	                'member_tier'  => $li['member_tier'] ?? ($context['member_tier'] ?? null),
121	                'package_code' => $li['package_code'] ?? ($context['package_code'] ?? null),
122	            ]);
123	            $resolved = $this->pricing->resolveUnitPrice($item, $basePrice, $lineCtx);
124	            $unitPrice = $resolved['unit_price'];
125	            $appliedRule = $resolved['rule'];
126	
127	            $lineSubtotal = round($unitPrice * $qty, 2);
128	            $lineTax = round($lineSubtotal * (float) $item->tax_rate, 2);
129	
130	            $lines[] = [
131	                'bookable_item_id' => $item->id,
132	                'item_name'        => $item->name,
133	                'booking_date'     => $li['booking_date'],
134	                'start_time'       => $li['start_time'] ?? null,
135	                'end_time'         => $li['end_time'] ?? null,
136	                'quantity'         => $qty,
137	                'unit_price'       => $unitPrice,
138	                'tax_rate'         => (float) $item->tax_rate,
139	                'line_subtotal'    => $lineSubtotal,
140	                'line_tax'         => $lineTax,
141	                'line_total'       => $lineSubtotal + $lineTax,
142	                'pricing_rule_id'  => $appliedRule?->id,
143	            ];
144	
145	            $subtotal += $lineSubtotal;
146	            $taxTotal += $lineTax;
147	        }
148	
149	        $discount = 0;
150	        $couponId = null;
151	        if ($couponCode) {
152	            $cv = $this->validateCoupon($couponCode, $subtotal);
153	            if ($cv['valid']) {
