156	            }
157	        }
158	
159	        return [
160	            'lines'     => $lines,
161	            'subtotal'  => round($subtotal, 2),
162	            'tax_amount' => round($taxTotal, 2),
163	            'discount'  => round($discount, 2),
164	            'total'     => round($subtotal + $taxTotal - $discount, 2),
165	            'coupon_id' => $couponId,
166	        ];
