170	    public function createOrder(int $userId, array $lineItems, ?int $groupLeaderId = null, ?int $serviceAreaId = null, ?string $couponCode = null, ?string $notes = null): Order
171	    {
172	        // Validate: a referenced group leader must actually hold that role + be active.
173	        if ($groupLeaderId !== null) {
174	            $leader = User::find($groupLeaderId);
175	            if (!$leader || !in_array($leader->role, ['group-leader', 'admin'], true) || !$leader->is_active) {
176	                throw ValidationException::withMessages([
177	                    'group_leader_id' => 'Assigned user is not an eligible group leader.',
178	                ]);
179	            }
180	
181	            // Enforce GroupLeaderAssignment: the leader must hold an active assignment
182	            // covering the order's service area. Admins bypass this check.
183	            // The check is skipped only if no service area is specified (free-form order).
184	            if ($leader->role !== 'admin' && $serviceAreaId !== null) {
185	                $assignment = GroupLeaderAssignment::where('user_id', $leader->id)
186	                    ->where('service_area_id', $serviceAreaId)
187	                    ->where('is_active', true)
188	                    ->first();
189	                if (!$assignment) {
190	                    throw ValidationException::withMessages([
191	                        'group_leader_id' => 'Group leader has no active assignment for this service area.',
192	                    ]);
193	                }
194	
195	                // Location binding (previously ignored despite both
196	                // bookable_items and group_leader_assignments carrying a
197	                // `location` column). Semantics:
198	                //   - Assignment.location NULL/empty  → leader covers all
199	                //     locations in the service area (no narrowing).
200	                //   - Assignment.location set         → every line item's
201	                //     bookable_item.location must match (trim, case-insensitive).
202	                //     Items with a NULL location are NOT covered by a
203	                //     location-bound assignment.
204	                $assignedLocation = $this->normalizeLocation($assignment->location);
205	                if ($assignedLocation !== null) {
206	                    $itemIds = array_values(array_unique(array_map(
207	                        fn ($li) => (int) ($li['bookable_item_id'] ?? 0),
208	                        $lineItems
209	                    )));
210	                    $itemLocations = BookableItem::whereIn('id', $itemIds)
211	                        ->pluck('location', 'id');
212	                    foreach ($itemIds as $iid) {
213	                        $itemLoc = $this->normalizeLocation($itemLocations[$iid] ?? null);
214	                        if ($itemLoc !== $assignedLocation) {
215	                            throw ValidationException::withMessages([
216	                                'group_leader_id' => 'Group leader is not assigned to the location of one or more booked items.',
217	                            ]);
218	                        }
219	                    }
220	                }
221	            }
222	        }
223	
224	        $conflicts = $this->detectConflicts($lineItems);
225	        if (!empty($conflicts)) {
226	            throw ValidationException::withMessages(['conflicts' => array_values($conflicts)]);
227	        }
228	
229	        // Build pricing context: user tier flows through the resolver automatically.
230	        $purchaser = User::find($userId);
231	        $context = [
232	            'member_tier' => PricingResolver::tierForUser($purchaser),
233	        ];
234	
235	        $totals = $this->calculateTotals($lineItems, $couponCode, $context);
236	
237	        return DB::transaction(function () use ($userId, $groupLeaderId, $serviceAreaId, $totals, $notes) {
238	            // Reservations enter the workflow as DRAFT. Customers must explicitly
239	            // submit-for-approval (draft → pending) and a profile-complete staff
240	            // member must approve (pending → confirmed). This guarantees no order
241	            // becomes financially binding without human review.
242	            $order = Order::create([
243	                'order_number'    => Order::generateOrderNumber(),
244	                'user_id'         => $userId,
245	                'group_leader_id' => $groupLeaderId,
246	                'service_area_id' => $serviceAreaId,
247	                'status'          => 'draft',
248	                'subtotal'        => $totals['subtotal'],
249	                'tax_amount'      => $totals['tax_amount'],
250	                'discount_amount' => $totals['discount'],
251	                'total'           => $totals['total'],
252	                'coupon_id'       => $totals['coupon_id'],
253	                'notes'           => $notes,
