276	    /** Transition order status with validation. */
277	    public function transitionOrder(Order $order, string $newStatus, ?string $reason = null): Order
278	    {
279	        // Reservation Approval Workflow
280	        //
281	        //   draft ──submit──▶ pending ──approve──▶ confirmed
282	        //                              ╲─reject──▶ cancelled
283	        //
284	        // After approval the order joins the existing operational lifecycle.
285	        $allowed = [
286	            'draft'       => ['pending', 'cancelled'],
287	            'pending'     => ['confirmed', 'cancelled'],
288	            'confirmed'   => ['checked_in', 'cancelled'],
289	            'checked_in'  => ['checked_out'],
290	            'checked_out' => ['completed'],
291	            'completed'   => ['refunded'],
292	            'cancelled'   => ['refunded'],
293	        ];
294	
295	        if (!isset($allowed[$order->status]) || !in_array($newStatus, $allowed[$order->status])) {
296	            throw ValidationException::withMessages(['status' => "Cannot transition from '{$order->status}' to '{$newStatus}'."]);
297	        }
298	
299	        $ts = match ($newStatus) {
300	            'pending'     => [], // submitted for approval; no timestamp column
301	            'confirmed'   => ['confirmed_at' => now()],
302	            'checked_in'  => ['checked_in_at' => now()],
303	            'checked_out' => ['checked_out_at' => now()],
304	            'cancelled'   => ['cancelled_at' => now(), 'cancellation_reason' => $reason],
305	            default       => [],
306	        };
307	
308	        $order->update(array_merge(['status' => $newStatus], $ts));
309	
310	        $this->audit->log("order_{$newStatus}", 'Order', $order->id, null, ['reason' => $reason]);
311	
312	        return $order->refresh();
313	    }
