12	/**
13	 * Session-based auth wrapper for Livewire web routes.
14	 * Validates the JWT stored in the session and hydrates the request
15	 * with auth_user, just like JwtAuthenticate does for API calls.
16	 */
17	class WebSessionAuth
18	{
19	    public function __construct(private readonly JwtService $jwt) {}
20	
21	    public function handle(Request $request, Closure $next): Response
22	    {
23	        $token = session('jwt_token');
24	
25	        if (!$token) {
26	            return redirect('/login');
27	        }
28	
29	        try {
30	            [$payload, $session] = $this->jwt->validateToken($token);
31	        } catch (\Throwable) {
32	            session()->forget(['jwt_token', 'auth_user_id', 'auth_user_name', 'auth_role']);
33	            return redirect('/login')->with('flash_error', 'Session expired. Please log in again.');
34	        }
35	
36	        $user = User::find($payload['sub']);
37	        if (!$user || !$user->is_active) {
38	            session()->flush();
39	            return redirect('/login')->with('flash_error', 'Account unavailable.');
40	        }
41	
42	        $request->attributes->set('auth_user', $user);
43	        $request->attributes->set('auth_session', $session);
44	        $request->attributes->set('auth_payload', $payload);
45	
46	        // CRITICAL: hydrate Laravel's auth guard so Gate::allows(), policies, and
47	        // any code that calls auth()->user() inside Livewire components can find
48	        // the authenticated user. Without this, OrderPolicy::view() etc. silently
49	        // receive null and deny everything in the web context.
50	        Auth::setUser($user);
51	
52	        return $next($request);
53	    }
54	}
