36	        // server-side filter (case-insensitive ILIKE on order_number) does
37	        // the work — no client-side filtering, no double-pagination bugs.
38	        $resp = $this->api()->get('/orders', [
39	            'status'   => $this->statusFilter ?: null,
40	            'search'   => $this->search ?: null,
41	            'page'     => $this->getPage(),
42	            'per_page' => 15,
43	        ]);
44	
45	        $payload = $resp->successful() ? $resp->json() : ['data' => [], 'total' => 0, 'current_page' => 1, 'last_page' => 1, 'per_page' => 15];
46	
47	        $orders = new LengthAwarePaginator(
48	            items: $payload['data'] ?? [],
49	            total: $payload['total'] ?? 0,
50	            perPage: $payload['per_page'] ?? 15,
51	            currentPage: $payload['current_page'] ?? 1,
52	            options: ['path' => request()->url()],
53	        );
