28	    public function generate(): void
29	    {
30	        $resp = $this->api()->post('/admin/settlements/generate', [
31	            'period_start' => $this->periodStart,
32	            'period_end'   => $this->periodEnd,
33	            'cycle_type'   => $this->cycleType,
34	        ]);
35	
36	        if ($resp->failed()) { $this->message = $resp->json('message') ?? 'Generation failed.'; return; }
37	        $data = $resp->json('data');
38	        $disc = $resp->json('discrepancies', []);
39	        $this->message = empty($disc)
40	            ? "Settlement {$data['reference']} generated and reconciled. Net: \${$data['net_amount']}"
41	            : "Settlement generated with " . count($disc) . " discrepancy(ies).";
42	    }
