14	class SettlementIndex extends Component
15	{
16	    use WithPagination, UsesApiClient;
17	
18	    public string $periodStart = '';
19	    public string $periodEnd = '';
20	    public string $cycleType = 'weekly';
21	    public string $message = '';
22	
23	    public function mount(): void
24	    {
25	        $this->periodStart = now()->startOfMonth()->toDateString();
26	        $this->periodEnd = now()->toDateString();
27	
28	        // Authorize at mount so abort(403) propagates as a hard 403
29	        // through Livewire's render harness. Doing the gate inside
30	        // render() lets Livewire wrap the HTTP exception in a soft
31	        // 200, which masks the denial in test assertions.
32	        $resp = $this->api()->get('/settlements');
33	        if ($resp->status() === 401) abort(401);
34	        if ($resp->status() === 403) abort(403);
35	    }
36	
37	    public function generate(): void
38	    {
39	        $resp = $this->api()->post('/admin/settlements/generate', [
40	            'period_start' => $this->periodStart,
41	            'period_end'   => $this->periodEnd,
42	            'cycle_type'   => $this->cycleType,
43	        ]);
44	
45	        if ($resp->failed()) { $this->message = $resp->json('message') ?? 'Generation failed.'; return; }
46	        $data = $resp->json('data');
47	        $disc = $resp->json('discrepancies', []);
48	        $this->message = empty($disc)
49	            ? "Settlement {$data['reference']} generated and reconciled. Net: \${$data['net_amount']}"
50	            : "Settlement generated with " . count($disc) . " discrepancy(ies).";
51	    }
52	
53	    public function finalize(int $id): void
54	    {
55	        $resp = $this->api()->post("/admin/settlements/{$id}/finalize");
56	        if ($resp->failed()) { $this->message = $resp->json('message') ?? 'Finalize failed.'; return; }
57	        $data = $resp->json('data');
58	        $this->message = "Settlement {$data['reference']} finalized.";
59	    }
60	
61	    public function render()
62	    {
63	        // Read through the API so authorization, role gating, and
64	        // row-level scoping are enforced uniformly with REST clients.
65	        // The /settlements endpoint is gated to role:staff (staff,
66	        // group-leader, and admin) by the API middleware and applies
67	        // row-level scoping inside SettlementService — Livewire never
68	        // touches the service or models directly.
69	        $resp = $this->api()->get('/settlements');
70	        if ($resp->status() === 401) abort(401);
71	        if ($resp->status() === 403) abort(403);
72	        $settlements = $resp->successful() ? ($resp->json() ?? []) : [];
73	
74	        return view('livewire.settlement.settlement-index', [
75	            'settlements' => $settlements,
76	            // Effective permissions are passed in so the blade can
77	            // gate buttons by the SAME slug the API enforces.
78	            'effectivePermissions' => $this->effectivePermissions(),
79	        ]);
80	    }
81	}
