            /** @var HttpKernel $kernel */
            $kernel = app(HttpKernel::class);
            $response = $kernel->handle($request);
        } catch (\Throwable $e) {
            // Render the exception through Laravel's handler so the
            // sub-request observes the same status code (404 / 422 /
            // 500) it would in production. Without this, an
            // uncaught ModelNotFoundException etc. propagates out of
            // the api() call and crashes the Livewire component
            // instead of letting it set a flash message from the
            // returned $resp->failed().
            $handler = app(\Illuminate\Contracts\Debug\ExceptionHandler::class);
            $response = $handler->render($request, $e);
        } finally {
            if ($previousDisable === null) {
                app()->forgetInstance('middleware.disable');
            } else {
                app()->instance('middleware.disable', $previousDisable);
            }
        }

