    private function renderExceptionResponse(\Throwable $e, IlluminateRequest $request): SymfonyResponse
    {
        if ($e instanceof \Illuminate\Database\Eloquent\ModelNotFoundException
            || $e instanceof \Symfony\Component\HttpKernel\Exception\NotFoundHttpException) {
            return response()->json(['message' => 'Resource not found.'], 404);
        }
        if ($e instanceof \Illuminate\Validation\ValidationException) {
            return response()->json([
                'message' => $e->getMessage(),
                'errors'  => $e->errors(),
            ], 422);
        }
        if ($e instanceof \Illuminate\Auth\Access\AuthorizationException
            || $e instanceof \Symfony\Component\HttpKernel\Exception\AccessDeniedHttpException) {
            return response()->json(['message' => $e->getMessage() ?: 'Forbidden.'], 403);
        }
        if ($e instanceof \Symfony\Component\HttpKernel\Exception\HttpExceptionInterface) {
            return response()->json(['message' => $e->getMessage()], $e->getStatusCode());
        }
        // Fallback: delegate to the framework handler — at minimum
        // this prevents the test runner from crashing on unexpected
        // domain exceptions.
        return app(\Illuminate\Contracts\Debug\ExceptionHandler::class)->render($request, $e);
    }
}

