        ]);
        $this->service->transitionOrder($order, 'pending');
        $this->assertSame(3, (int) $consumable->fresh()->stock);
        $this->service->transitionOrder($order, 'cancelled', 'reason');
        $this->assertSame(5, (int) $consumable->fresh()->stock);
    }
}"}

